     1→import React, { useEffect, useState, useCallback } from "react";
     2→import { useNavigate } from "react-router-dom";
     3→import { View, Text, ActivityIndicator, StyleSheet } from "../primitives";
     4→import { fetchSessions, subscribeToUpdates, type Session } from "../api";
     5→import { SessionRow, COL_WIDTHS } from "../components/SessionRow";
     6→
     7→const COLUMNS: { label: string; width: number }[] = [
     8→  { label: "Session",  width: COL_WIDTHS.session  },
     9→  { label: "User",     width: COL_WIDTHS.user     },
    10→  { label: "Repo",     width: COL_WIDTHS.repo     },
    11→  { label: "Summary",  width: COL_WIDTHS.summary  },
    12→  { label: "Keywords", width: COL_WIDTHS.keywords },
    13→  { label: "Started",  width: COL_WIDTHS.started  },
    14→  { label: "Updated",  width: COL_WIDTHS.updated  },
    15→];
    16→
    17→const TOTAL_WIDTH = Object.values(COL_WIDTHS).reduce((a, b) => a + b, 0) + 16;
    18→
    19→export function ActiveSessions() {
    20→  const navigate = useNavigate();
    21→  const [sessions, setSessions] = useState<Session[]>([]);
    22→  const [loading, setLoading] = useState(true);
    23→  const [error, setError] = useState<string | null>(null);
    24→
    25→  const load = useCallback(async () => {
    26→    try {
    27→      setSessions(await fetchSessions());
    28→      setError(null);
    29→    } catch (err) {
    30→      setError(String(err));
    31→    }
    32→  }, []);
    33→
    34→  useEffect(() => {
    35→    load().finally(() => setLoading(false));
    36→    return subscribeToUpdates(() => { load().catch(() => undefined); });
    37→  }, [load]);
    38→
    39→  if (loading) {
    40→    return (
    41→      <View style={styles.centered}>
    42→        <ActivityIndicator color="#6366f1" />
    43→      </View>
    44→    );
    45→  }
