    16→
    17→type DisplayItem =
    18→  | { kind: "event"; event: Event }
    19→  | { kind: "toolGroup"; tools: ToolUseData[] }
    20→  | { kind: "checkpoint"; checkpoint: SessionCheckpoint };
    21→
    22→function groupEvents(events: Event[]): DisplayItem[] {
    23→  const postMap = new Map<string, Event>();
    24→  for (const event of events) {
    25→    if (event.event === "PostToolUse" || event.event === "PostToolUseFailure") {
    26→      const d = event.data as Record<string, unknown>;
    27→      const id = typeof d.tool_use_id === "string" ? d.tool_use_id : null;
    28→      if (id) postMap.set(id, event);
    29→    }
    30→  }
    31→
    32→  type RawItem =
    33→    | { kind: "event"; event: Event }
    34→    | { kind: "toolUse"; pre: Event; post?: Event; failed: boolean };
    35→
    36→  const raw: RawItem[] = [];
    37→  const consumed = new Set<number>();
    38→
    39→  for (const event of events) {
    40→    if ((event.event === "PostToolUse" || event.event === "PostToolUseFailure") && consumed.has(event.id)) continue;
    41→    if (event.event === "PreToolUse") {
    42→      const d = event.data as Record<string, unknown>;
    43→      const toolUseId = typeof d.tool_use_id === "string" ? d.tool_use_id : null;
    44→      const post = toolUseId ? postMap.get(toolUseId) : undefined;
    45→      if (post) consumed.add(post.id);
    46→      raw.push({ kind: "toolUse", pre: event, post, failed: post?.event === "PostToolUseFailure" });
    47→      continue;
    48→    }
    49→    raw.push({ kind: "event", event });
    50→  }
    51→
    52→  const isGroupable = (item: RawItem) =>
    53→    item.kind === "toolUse" || (item.kind === "event" && item.event.event === "Notification");
    54→
    55→  const result: DisplayItem[] = [];
    56→  let i = 0;
    57→  while (i < raw.length) {
    58→    if (isGroupable(raw[i])) {
    59→      const group: ToolUseData[] = [];
    60→      while (i < raw.length && isGroupable(raw[i])) {
    61→        const item = raw[i];
    62→        if (item.kind === "toolUse") group.push({ pre: item.pre, post: item.post, failed: item.failed });
    63→        i++;
    64→      }
    65→      if (group.length > 0) result.push({ kind: "toolGroup", tools: group });
    66→    } else {
    67→      result.push({ kind: "event", event: (raw[i] as { kind: "event"; event: Event }).event });
    68→      i++;
    69→    }
    70→  }
    71→  return result;
    72→}
    73→
    74→function CheckpointRow({ checkpoint, onPress }: { checkpoint: SessionCheckpoint; onPress: () => void }) {
    75→  const [expanded, setExpanded] = useState(false);
