    78→  const sum = checkpoint.summary;
    79→
    80→  return (
    81→    <div style={{ borderLeft: "4px solid #059669" }}>
    82→      <TouchableOpacity onPress={() => setExpanded((v) => !v)} style={styles.cpRow}>
