    88→          </View>
    89→          {sum?.intent && (
    90→            <div style={{ ...styles.cpIntent, WebkitLineClamp: expanded ? undefined : 1, display: expanded ? "block" : "-webkit-box", WebkitBoxOrient: "vertical", overflow: "hidden" } as React.CSSProperties}>
    91→              {sum.intent}
    92→            </div>
    93→          )}
    94→        </View>
    95→        <View style={styles.cpMeta}>
    96→          {fileCount > 0 && <span style={styles.cpMetaText}>{fileCount} file{fileCount !== 1 ? "s" : ""}</span>}
    97→          {outTokens > 0 && <span style={styles.cpMetaText}>{outTokens.toLocaleString()} tok</span>}
    98→        </View>
    99→      </TouchableOpacity>
   100→
   101→      {expanded && (
   102→        <View style={styles.cpDropdown}>
   103→          {sum?.outcome && <View style={styles.cpSection}><span style={styles.cpSectionLabel}>✓ Outcome</span><span style={styles.cpSectionText}>{sum.outcome}</span></View>}
   104→          {sum?.repoLearnings?.length ? <View style={styles.cpSection}><span style={styles.cpSectionLabel}>◎ Repo learnings</span>{sum.repoLearnings.map((it, i) => <span key={i} style={styles.cpBullet}>· {it}</span>)}</View> : null}
   105→          {sum?.codeLearnings?.length ? <View style={styles.cpSection}><span style={styles.cpSectionLabel}>{"</>"} Code learnings</span>{sum.codeLearnings.map((it, i) => <View key={i} style={styles.cpCodeLearning}><span style={styles.cpCodePath}>{it.path}</span><span style={styles.cpBullet}>{it.finding}</span></View>)}</View> : null}
   106→          {sum?.workflowLearnings?.length ? <View style={styles.cpSection}><span style={styles.cpSectionLabel}>↺ Workflow learnings</span>{sum.workflowLearnings.map((it, i) => <span key={i} style={styles.cpBullet}>· {it}</span>)}</View> : null}
   107→          {sum?.friction?.length ? <View style={styles.cpSection}><span style={styles.cpSectionLabel}>△ Friction</span>{sum.friction.map((it, i) => <span key={i} style={styles.cpBullet}>· {it}</span>)}</View> : null}
   108→          {sum?.openItems?.length ? <View style={styles.cpSection}><span style={styles.cpSectionLabel}>◇ Open items</span>{sum.openItems.map((it, i) => <span key={i} style={styles.cpBullet}>· {it}</span>)}</View> : null}
