     8→  depth: number;
     9→  hasChildren: boolean;
    10→  isLast: boolean;
    11→}
    12→
    13→function buildChildMap(sessions: Session[]): Map<string | null, Session[]> {
    14→  const map = new Map<string | null, Session[]>();
    15→  for (const s of sessions) {
    16→    const key = s.parentSessionId;
    17→    if (!map.has(key)) map.set(key, []);
    18→    map.get(key)!.push(s);
    19→  }
    20→  for (const arr of map.values()) {
    21→    arr.sort((a, b) => (a.startedAt < b.startedAt ? 1 : -1));
    22→  }
    23→  return map;
    24→}
    25→
    26→function flatten(
    27→  parentId: string | null,
    28→  childMap: Map<string | null, Session[]>,
    29→  depth: number,
    30→  expanded: Set<string>,
    31→  out: FlatNode[],
    32→) {
    33→  const siblings = childMap.get(parentId) ?? [];
    34→  for (let i = 0; i < siblings.length; i++) {
    35→    const session = siblings[i];
    36→    const hasChildren = (childMap.get(session.sessionId) ?? []).length > 0;
    37→    out.push({ session, depth, hasChildren, isLast: i === siblings.length - 1 });
    38→    if (hasChildren && expanded.has(session.sessionId)) {
    39→      flatten(session.sessionId, childMap, depth + 1, expanded, out);
    40→    }
    41→  }
    42→}
    43→
    44→function relativeTime(iso: string): string {
    45→  const diff = Date.now() - new Date(iso).getTime();
    46→  const secs = Math.floor(diff / 1000);
    47→  if (secs < 60) return `${secs}s ago`;
    48→  if (secs < 3600) return `${Math.floor(secs / 60)}m ago`;
    49→  if (secs < 86400) return `${Math.floor(secs / 3600)}h ago`;
    50→  return `${Math.floor(secs / 86400)}d ago`;
    51→}
    52→
    53→function activityColor(iso: string): string {
    54→  const diff = Date.now() - new Date(iso).getTime();
    55→  if (diff < 2 * 60 * 1000) return "#22c55e";
    56→  if (diff < 15 * 60 * 1000) return "#f59e0b";
    57→  return "#d1d5db";
    58→}
    59→
    60→const INDENT = 22;
    61→
    62→function TreeNode({
    63→  node,
    64→  isExpanded,
    65→  onPress,
    66→  onToggle,
    67→}: {
    68→  node: FlatNode;
    69→  isExpanded: boolean;
    70→  onPress: () => void;
    71→  onToggle: () => void;
    72→}) {
    73→  const { session, depth, hasChildren } = node;
    74→  const dotColor = activityColor(session.updatedAt);
    75→
    76→  return (
    77→    <TouchableOpacity
    78→      style={{ ...s.row, paddingLeft: 12 + depth * INDENT } as React.CSSProperties}
    79→      onPress={onPress}
