    81→      <div
    82→        role="button"
    83→        tabIndex={0}
    84→        onClick={(e) => { e.stopPropagation(); hasChildren ? onToggle() : onPress(); }}
    85→        onKeyDown={(e) => e.key === "Enter" && (hasChildren ? onToggle() : onPress())}
    86→        style={s.toggleWrap}
    87→      >
    88→        {hasChildren ? (
    89→          <span style={s.chevron}>{isExpanded ? "▼" : "▶"}</span>
    90→        ) : (
    91→          <div style={{ ...s.leaf, backgroundColor: dotColor } as React.CSSProperties} />
    92→        )}
    93→      </div>
    94→
    95→      {hasChildren && <div style={{ ...s.dot, backgroundColor: dotColor } as React.CSSProperties} />}
    96→
    97→      <View style={s.content}>
    98→        <View style={s.titleRow}>
    99→          <span style={s.sessionId}>{session.sessionId.slice(0, 8)}</span>
   100→          {session.repoName && <span style={s.repoChip}>{session.repoName}</span>}
   101→          <span style={s.time}>{relativeTime(session.updatedAt)}</span>
   102→        </View>
   103→        {session.summary && (
   104→          <div style={s.summary}>{session.summary}</div>
   105→        )}
   106→        {session.keywords.length > 0 && (
   107→          <View style={s.keywords}>
   108→            {session.keywords.slice(0, 5).map((k) => (
   109→              <span key={k} style={s.keyword}>{k}</span>
   110→            ))}
   111→          </View>
   112→        )}
   113→      </View>
   114→    </TouchableOpacity>
   115→  );
   116→}
   117→
   118→export function SessionTree() {
   119→  const navigate = useNavigate();
   120→  const [sessions, setSessions] = useState<Session[]>([]);
   121→  const [loading, setLoading] = useState(true);
   122→  const [error, setError] = useState<string | null>(null);
   123→  const [expanded, setExpanded] = useState<Set<string>>(new Set());
   124→
   125→  const load = useCallback(async () => {
   126→    try {
   127→      const data = await fetchSessions();
   128→      setSessions(data);
   129→      setError(null);
   130→      setExpanded((prev) => {
   131→        const next = new Set(prev);
   132→        const parentIds = new Set(data.map((sess) => sess.parentSessionId).filter(Boolean));
   133→        for (const id of parentIds) if (id) next.add(id);
   134→        return next;
   135→      });
   136→    } catch (e) {
   137→      setError(String(e));
   138→    }
   139→  }, []);
   140→
   141→  useEffect(() => {
   142→    load().finally(() => setLoading(false));
   143→    return subscribeToUpdates(() => { load().catch(() => undefined); });
   144→  }, [load]);
   145→
   146→  const childMap = useMemo(() => buildChildMap(sessions), [sessions]);
   147→  const nodes = useMemo(() => {
   148→    const out: FlatNode[] = [];
   149→    flatten(null, childMap, 0, expanded, out);
   150→    return out;
   151→  }, [childMap, expanded]);
   152→
   153→  function toggle(sessionId: string) {
   154→    setExpanded((prev) => {
   155→      const next = new Set(prev);
   156→      if (next.has(sessionId)) next.delete(sessionId);
   157→      else next.add(sessionId);
   158→      return next;
   159→    });
   160→  }
   161→
   162→  if (loading) return <View style={s.centered}><div style={{ color: "#9ca3af" }}>Loading…</div></View>;
   163→  if (error) return <View style={s.centered}><div style={{ color: "#ef4444" }}>{error}</div></View>;
   164→  if (nodes.length === 0) return <View style={s.centered}><div style={{ color: "#9ca3af" }}>No sessions yet.</div></View>;
   165→
   166→  return (
   167→    <div style={{ flex: 1, overflow: "auto", backgroundColor: "#fff" }}>
   168→      {nodes.map((node) => (
   169→        <div key={node.session.sessionId} style={{ position: "relative" }}>
   170→          {node.depth > 0 && (
   171→            <div style={{
   172→              position: "absolute",
   173→              top: 0,
   174→              left: 12 + (node.depth - 1) * INDENT + 9,
   175→              width: 1,
   176→              height: "100%",
   177→              backgroundColor: "#e5e7eb",
   178→            }} />
   179→          )}
   180→          <TreeNode
   181→            node={node}
   182→            isExpanded={expanded.has(node.session.sessionId)}
   183→            onPress={() =>
   184→              navigate(`/sessions/${node.session.sessionId}`, {
   185→                state: { title: node.session.summary ?? node.session.sessionId.slice(0, 8) + "…" },
   186→              })
   187→            }
   188→            onToggle={() => toggle(node.session.sessionId)}
   189→          />
   190→        </div>
   191→      ))}
   192→    </div>
   193→  );
   194→}
   195→
   196→const s = StyleSheet.create({
   197→  centered: { flex: 1, alignItems: "center", justifyContent: "center", padding: 24 } as React.CSSProperties,
   198→  row: {
   199→    display: "flex",
   200→    flexDirection: "row",
   201→    alignItems: "flex-start",
   202→    paddingTop: 10,
   203→    paddingBottom: 10,
   204→    paddingRight: 16,
   205→    borderBottom: "1px solid #f1f5f9",
   206→    gap: 8,
   207→    cursor: "pointer",
   208→  } as React.CSSProperties,
   209→  toggleWrap: { width: 18, display: "flex", alignItems: "center", paddingTop: 2, flexShrink: 0, cursor: "pointer" } as React.CSSProperties,
   210→  chevron: { fontSize: 10, color: "#9ca3af" } as React.CSSProperties,
   211→  leaf: { width: 7, height: 7, borderRadius: "50%", marginTop: 4 } as React.CSSProperties,
   212→  dot: { width: 8, height: 8, borderRadius: "50%", marginTop: 3, flexShrink: 0 } as React.CSSProperties,
   213→  content: { flex: 1, gap: 3 } as React.CSSProperties,
   214→  titleRow: { flexDirection: "row", alignItems: "center", gap: 6, flexWrap: "wrap" } as React.CSSProperties,
