   159→        orderBy: { createdAt: "desc" },
   160→      });
   161→      const branchMap = new Map<string, string | null>();
   162→      const intentMap = new Map<string, string | null>();
   163→      for (const m of sessionMetas) {
   164→        if (!branchMap.has(m.sessionId)) branchMap.set(m.sessionId, m.branch);
   165→        if (!intentMap.has(m.sessionId)) intentMap.set(m.sessionId, m.summary?.intent ?? null);
   166→      }
   167→
   168→      // Build parent → children map in memory
   169→      const childMap = new Map<string, string[]>();
   170→      for (const s of sessions) {
   171→        if (s.parentSessionId) {
