   537→        createdAt:    s.createdAt?.toISOString() ?? null,
   538→        tokenUsage:   s.tokenUsage ? {
   539→          inputTokens:         s.tokenUsage.inputTokens,
   540→          cacheCreationTokens: s.tokenUsage.cacheCreationTokens,
   541→          cacheReadTokens:     s.tokenUsage.cacheReadTokens,
   542→          outputTokens:        s.tokenUsage.outputTokens,
   543→          apiCallCount:        s.tokenUsage.apiCallCount,
   544→        } : null,
   545→        filesTouched: s.filesTouched.map((f) => f.filePath.path),
   546→        summary:      s.summary ? mapV2Summary(s.summary) : null,
   547→      })));
   548→    } catch (err) {
   549→      res.status(500).json({ error: String(err) });
   550→    }
   551→  });
   552→
   553→  // Create HTTP server and attach WebSocket server (shared port)
   554→  const httpServer = createServer(app);
   555→  const wss = new WebSocketServer({ server: httpServer });
   556→
   557→  // WebSocket change detection — poll every 2s, broadcast on new events or checkpoints
   558→  let lastMaxEventId: number | null = null;
   559→  let lastMaxCheckpointId: number | null = null;
   560→  const broadcast = () => {
   561→    const message = JSON.stringify({ type: "sessions_updated" });
   562→    for (const client of wss.clients) {
   563→      if (client.readyState === WebSocket.OPEN) {
   564→        client.send(message);
   565→      }
   566→    }
   567→  };
   568→  const poller = setInterval(async () => {
   569→    try {
   570→      const [latestEvent, latestCheckpoint] = await Promise.all([
   571→        db.event.findFirst({ orderBy: { id: "desc" }, select: { id: true } }),
   572→        db.checkpointMetadata.findFirst({ orderBy: { id: "desc" }, select: { id: true } }),
   573→      ]);
   574→      const currentEventId = latestEvent?.id ?? null;
   575→      const currentCheckpointId = latestCheckpoint?.id ?? null;
   576→      if (currentEventId !== lastMaxEventId || currentCheckpointId !== lastMaxCheckpointId) {
   577→        lastMaxEventId = currentEventId;
   578→        lastMaxCheckpointId = currentCheckpointId;
   579→        broadcast();
   580→      }
   581→    } catch {
   582→      // Non-fatal polling error — keep running
   583→    }
   584→  }, 2000);
   585→
   586→  // ── Checkpoint auto-indexer ───────────────────────────────────────────────
   587→
   588→  const WORKTREE_PATH = "/tmp/gossamer-checkpoints";
   589→  const CHECKPOINT_BRANCH = "entire/checkpoints/v1";
   590→  let checkpointPoller: ReturnType<typeof setInterval> | null = null;
   591→
   592→  if (repoDir) {
   593→    // Ensure worktree exists (reuse across restarts)
   594→    if (!existsSync(WORKTREE_PATH)) {
   595→      try {
   596→        // Prune stale worktree registration first, then re-add
   597→        execSync(`git -C ${JSON.stringify(repoDir)} worktree prune`, { stdio: "pipe" });
   598→        execSync(
   599→          `git -C ${JSON.stringify(repoDir)} worktree add ${JSON.stringify(WORKTREE_PATH)} ${CHECKPOINT_BRANCH}`,
   600→          { stdio: "pipe" },
   601→        );
   602→        process.stderr.write(`checkpoint indexer: worktree created at ${WORKTREE_PATH}\n`);
   603→      } catch (err) {
   604→        process.stderr.write(`checkpoint indexer: failed to create worktree — ${err}\n`);
   605→      }
   606→    }
   607→
   608→    const runIndex = async () => {
   609→      if (!existsSync(WORKTREE_PATH)) return;
   610→      try {
   611→        // Pull latest commits into the worktree working tree
   612→        execSync(`git -C ${JSON.stringify(WORKTREE_PATH)} reset --hard HEAD`, { stdio: "pipe" });
   613→      } catch { /* non-fatal */ }
   614→      try {
   615→        const { newMessages } = await indexAllCheckpoints(db, WORKTREE_PATH);
   616→        if (newMessages > 0) {
   617→          process.stderr.write(`checkpoint indexer: +${newMessages} new messages\n`);
   618→          broadcast();
   619→        }
   620→      } catch { /* non-fatal */ }
   621→      try {
   622→        const { checkpoints } = await indexAllCheckpointsV2(db, WORKTREE_PATH);
   623→        if (checkpoints > 0) {
   624→          process.stderr.write(`checkpoint indexer v2: indexed ${checkpoints} checkpoints\n`);
   625→          broadcast();
   626→        }
   627→      } catch { /* non-fatal */ }
   628→    };
   629→
   630→    void runIndex();
   631→    checkpointPoller = setInterval(runIndex, 30_000);
   632→    process.stderr.write(`checkpoint indexer: polling every 30s (worktree: ${WORKTREE_PATH})\n`);
   633→  }
   634→
   635→  // Graceful shutdown
   636→  const shutdown = () => {
   637→    clearInterval(poller);
   638→    if (checkpointPoller) clearInterval(checkpointPoller);
   639→    httpServer.close();
   640→    process.exit(0);
   641→  };
   642→  process.on("SIGINT", shutdown);
   643→  process.on("SIGTERM", shutdown);
   644→
   645→  await new Promise<void>((resolve) => {
   646→    httpServer.listen(port, () => {
   647→      process.stderr.write(`claude-hook-handler serve: listening on http://localhost:${port}\n`);
   648→      resolve();
   649→    });
   650→  });
   651→}
