import { MantineProvider, createTheme, localStorageColorSchemeManager } from "@mantine/core";
import "@mantine/core/styles.css";
import App from "./App";

const colorSchemeManager = localStorageColorSchemeManager({ key: "gossamer-color-scheme" });

