              <Text size="xs" fw={700} tt="uppercase" style={{ letterSpacing: 0.5, marginTop: 6, marginBottom: 2 }} c={failed ? "red" : "dimmed"}>
                {failed ? "error" : "output"}
              </Text>
              <Code block style={{ fontSize: 11 }}>{outputStr}</Code>
            </>
          )}
        </Box>
      </Collapse>
    </Box>
  );
}

